                filter_all: 'Alle Touren', filter_multi: 'Mehrtägig', filter_day: 'Tagesausflüge',
                sec1_label: 'Übernachtungsexpeditionen', sec1_h: 'Mehrtägige Touren',
                sec1_sub: 'Bleiben Sie lange genug, um den Rhythmus des Waldes zu spüren. Jede mehrtägige Route kombiniert Wildtierbeobachtung, Dschungelspaziergänge und Flussfahrten unter der Leitung eines Naturalistenspezialisten.',
                sec2_label: 'Noch am selben Tag zurück', sec2_h: 'Tagesausflüge',
                sec2_sub: 'Ganztägige Routen ab Manaus ohne Übernachtung. Ideal vor oder nach einer längeren Reise oder als eigenständiges Amazonas-Erlebnis.',
                view_tour: 'Tour ansehen', enquire: 'Anfragen', day_badge: 'Tagesausflug',
                ae_desc: 'Fünf Tage im Rio-Negro-Becken: Aussichtsturm im Baumkronendach bei Morgengrauen, Igapó-Überschwemmungswald per Kanu, fünf Nächte zwischen Öko-Lodge und Flussboot. Vorbei am Territorium des rosa Flussdelfins, einem indigenen Dorf und jeder Moment begleitet von einem Naturalistenspezialisten.',
                ae_hl1: 'Baumkronenturm Ducke-Reservat bei erstem Licht', ae_hl2: 'Territorium des rosa Flussdelfins, Rio Negro', ae_hl3: 'Besuch eines indigenen Dorfes',
                re_desc: 'Fünf Tage flussaufwärts am Rio Negro, vom MUSA-Baumkronen-Aussichtsturm bei Morgengrauen bis zum Territorium des rosa Flussdelfins am Nachmittag. Der Anavilhanas-Nationalpark und die Chance, Uacari-Affen zu entdecken, prägen die mittleren Tage.',
                re_hl1: 'MUSA-Aussichtsturm zur Baumkronenbeobachtung', re_hl2: 'Territorium des Rotrücken-Uacari-Affen', re_hl3: 'Anavilhanas-Nationalpark',
