                tc5_dur: '5 Días / 4 Noches',
                tc6_p: 'La expedición original. Cinco días de torres de dosel, comunidades ribereñas, caminatas nocturnas y tiempo en bosque primario fuera de la ruta turística.',
                view_tour: 'Ver tour', badge_lodge: 'Lodge', badge_riverboat: 'Barco fluvial',
