                exc4: `<i class="fa-solid fa-circle-xmark"></i> Seguro de viaje`,
                gtk_title: `Conviene saber`,
                gtk1: `<i class="fa-solid fa-language"></i> Guías hablan EN, DE, PT y ES`,
